module shift_register (
    input clk,
    input load,
    input [7:0] data_in,
    output reg [7:0] q
);

    // Shift register logic
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (load)
            q <= data_in;
        else
            q <= {q[6:0], 1'b0}; // Shift left
    end

endmodule
